import { useEffect, useMemo, useState } from "react";
import api from "../api";

const PAGE_SIZE = 10;
const CONTRACT_TYPES = [
    { value: "CONSTRUCTION", label: "Thi công" },
    { value: "SERVICE", label: "Dịch vụ" },
    { value: "SUPPLY", label: "Cung cấp" },
];
const CONTRACT_STATUSES = [
    { value: "ACTIVE", label: "Đang thực hiện" },
    { value: "PENDING", label: "Chờ duyệt/Ký" },
    { value: "COMPLETED", label: "Đã hoàn tất" },
    { value: "CANCELLED", label: "Đã huỷ" },
];

function normalizePage(d) {
    return Array.isArray(d)
        ? { list: d, pages: 1, total: d.length }
        : {
            list: d?.content || [],
            pages: d?.totalPages || 1,
            total: d?.totalElements ?? (d?.content?.length ?? 0),
        };
}

function fmtMoney(n) {
    if (n == null) return "—";
    try {
        return Number(n).toLocaleString("vi-VN");
    } catch {
        return String(n);
    }
}
function ymd(date) {
    if (!date) return "";
    const d = new Date(date);
    if (Number.isNaN(d.getTime())) return date;
    const mm = String(d.getMonth() + 1).padStart(2, "0");
    const dd = String(d.getDate()).padStart(2, "0");
    return `${d.getFullYear()}-${mm}-${dd}`;
}
function today() {
    return ymd(new Date());
}
function genCode() {
    const d = new Date();
    const y = d.getFullYear();
    const m = String(d.getMonth() + 1).padStart(2, "0");
    const day = String(d.getDate()).padStart(2, "0");
    const rnd = Math.floor(1000 + Math.random() * 9000);
    return `HD-${y}${m}${day}-${rnd}`;
}

export default function Contracts() {
    const [rows, setRows] = useState([]);
    const [page, setPage] = useState(0);
    const [pages, setPages] = useState(1);
    const [loading, setLoading] = useState(true);

    const [customers, setCustomers] = useState([]);
    const customerMap = useMemo(() => {
        const m = new Map();
        customers.forEach((c) => m.set(c.id, c.name || c.fullName || c.customerName));
        return m;
    }, [customers]);

    const [show, setShow] = useState(false);
    const [editing, setEditing] = useState(null);
    const [form, setForm] = useState({
        contractCode: genCode(),
        title: "",
        contractType: "CONSTRUCTION",
        customerId: "",
        signedDate: today(),
        dueDate: "",
        totalAmount: "",
        status: "ACTIVE",
    });

    useEffect(() => {
        loadContracts();
    }, [page]);

    useEffect(() => {
        // tải list KH cho dropdown
        (async () => {
            try {
                const { data } = await api.get("/api/customers", {
                    params: { page: 0, size: 1000, sort: "id,desc" },
                });
                const { list } = normalizePage(data);
                setCustomers(
                    list.map((c) => ({
                        id: c.id,
                        name: c.name || c.fullName || c.customerName || `#${c.id}`,
                    }))
                );
            } catch (e) {
                console.error("Load customers failed", e);
                setCustomers([]);
            }
        })();
    }, []);

    async function loadContracts() {
        setLoading(true);
        try {
            const { data } = await api.get("/api/contracts", {
                params: { page, size: PAGE_SIZE, sort: "id,desc" },
            });
            const { list, pages: p } = normalizePage(data);
            // chuẩn hoá hiển thị
            setRows(
                list.map((r) => ({
                    id: r.id,
                    contractCode: r.contractCode,
                    title: r.title,
                    contractType: r.contractType,
                    customerId: r.customerId,
                    customerName: r.customerName,
                    signedDate: r.signedDate,
                    dueDate: r.dueDate,
                    totalAmount: r.totalAmount,
                    paidAmount: r.paidAmount,
                    remainingAmount: r.remainingAmount,
                    status: r.status,
                }))
            );
            setPages(p);
        } catch (e) {
            console.error(e);
            setRows([]);
            setPages(1);
        } finally {
            setLoading(false);
        }
    }

    function openCreate() {
        setEditing(null);
        setForm({
            contractCode: genCode(),
            title: "",
            contractType: "CONSTRUCTION",
            customerId: customers[0]?.id || "",
            signedDate: today(),
            dueDate: "",
            totalAmount: "",
            status: "ACTIVE",
        });
        setShow(true);
    }

    function openEdit(row) {
        setEditing(row);
        setForm({
            contractCode: row.contractCode || genCode(),
            title: row.title || "",
            contractType: row.contractType || "CONSTRUCTION",
            customerId: row.customerId || "",
            signedDate: ymd(row.signedDate) || today(),
            dueDate: ymd(row.dueDate) || "",
            totalAmount: row.totalAmount ?? "",
            status: row.status || "ACTIVE",
        });
        setShow(true);
    }

    async function save(e) {
        e.preventDefault();
        const payload = {
            contractCode: form.contractCode?.trim(),
            title: form.title?.trim(),
            contractType: form.contractType,
            customerId: Number(form.customerId),
            signedDate: form.signedDate,
            dueDate: form.dueDate || null,
            totalAmount: Number(form.totalAmount),
            status: form.status,
        };

        try {
            if (editing) {
                await api.put(`/api/contracts/${editing.id}`, payload);
            } else {
                await api.post("/api/contracts", payload);
            }
            setShow(false);
            await loadContracts();
        } catch (err) {
            alert(
                err?.response?.data?.message ||
                err?.response?.data?.error ||
                JSON.stringify(err?.response?.data) ||
                "Lưu hợp đồng thất bại"
            );
            console.error(err);
        }
    }

    async function remove(row) {
        if (!window.confirm(`Xoá hợp đồng ${row.contractCode}?`)) return;
        try {
            await api.delete(`/api/contracts/${row.id}`);
            await loadContracts();
        } catch (err) {
            alert(
                err?.response?.data?.message ||
                err?.response?.data?.error ||
                "Xoá hợp đồng thất bại"
            );
            console.error(err);
        }
    }

    return (
        <div className="space-y-5">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-lg font-semibold">Hợp đồng</h2>
                    <p className="text-sm text-slate-500">Theo dõi mã, loại, giá trị và trạng thái</p>
                </div>
                <button
                    onClick={openCreate}
                    className="px-4 py-2 rounded-xl bg-indigo-600 text-white hover:bg-indigo-700"
                >
                    Thêm hợp đồng
                </button>
            </div>

            {/* List */}
            <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-4">
                {loading ? (
                    <div className="text-sm text-slate-500">Đang tải…</div>
                ) : rows.length === 0 ? (
                    <div className="text-sm text-slate-500">Chưa có hợp đồng</div>
                ) : (
                    rows.map((c) => (
                        <div
                            key={c.id}
                            className="rounded-2xl border border-indigo-100 bg-white shadow p-4 flex flex-col gap-2"
                        >
                            <div className="flex items-start justify-between">
                                <div>
                                    <div className="font-semibold text-indigo-700">{c.contractCode}</div>
                                    <div className="text-sm text-slate-600">{c.title || "—"}</div>
                                    <div className="text-xs text-slate-500">
                                        {c.contractType} • KH: {c.customerName || customerMap.get(c.customerId) || c.customerId}
                                    </div>
                                </div>
                                <span
                                    className={
                                        "px-2 py-0.5 text-xs rounded-full " +
                                        (c.status === "ACTIVE"
                                            ? "bg-amber-100 text-amber-700"
                                            : c.status === "COMPLETED"
                                                ? "bg-emerald-100 text-emerald-700"
                                                : c.status === "PENDING"
                                                    ? "bg-sky-100 text-sky-700"
                                                    : "bg-slate-100 text-slate-700")
                                    }
                                >
                  {c.status}
                </span>
                            </div>

                            <div className="grid grid-cols-3 gap-2 text-sm">
                                <div className="bg-indigo-50/50 rounded-xl p-2">
                                    <div className="text-xs text-slate-500">Giá trị</div>
                                    <div className="font-semibold">{fmtMoney(c.totalAmount)} đ</div>
                                </div>
                                <div className="bg-indigo-50/50 rounded-xl p-2">
                                    <div className="text-xs text-slate-500">Đã thu</div>
                                    <div className="font-semibold">{fmtMoney(c.paidAmount)} đ</div>
                                </div>
                                <div className="bg-indigo-50/50 rounded-xl p-2">
                                    <div className="text-xs text-slate-500">Còn lại</div>
                                    <div className="font-semibold">{fmtMoney(c.remainingAmount)} đ</div>
                                </div>
                            </div>

                            <div className="text-xs text-slate-500">
                                Ký: {ymd(c.signedDate)} • Đến hạn: {ymd(c.dueDate)}
                            </div>

                            <div className="mt-1 flex gap-2 justify-end">
                                <button
                                    onClick={() => openEdit(c)}
                                    className="px-2 py-1 rounded bg-indigo-50 text-indigo-700 hover:bg-indigo-100 text-sm"
                                >
                                    Sửa
                                </button>
                                <button
                                    onClick={() => remove(c)}
                                    className="px-2 py-1 rounded bg-rose-50 text-rose-700 hover:bg-rose-100 text-sm"
                                >
                                    Xoá
                                </button>
                            </div>
                        </div>
                    ))
                )}
            </div>

            {/* Pagination */}
            <div className="flex items-center gap-2">
                <button
                    className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                    onClick={() => setPage((p) => Math.max(0, p - 1))}
                    disabled={page <= 0}
                >
                    ← Trước
                </button>
                <div className="px-3 py-1.5 text-sm">Trang {page + 1}/{pages}</div>
                <button
                    className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                    onClick={() => setPage((p) => p + 1)}
                    disabled={page + 1 >= pages}
                >
                    Sau →
                </button>
            </div>

            {/* Modal */}
            {show && (
                <div className="fixed inset-0 z-40 bg-black/40 grid place-items-center p-4">
                    <div className="w-full max-w-3xl bg-white rounded-2xl shadow-xl border border-indigo-100">
                        <div className="p-5 border-b flex items-center justify-between">
                            <div className="font-semibold">{editing ? "Sửa hợp đồng" : "Thêm hợp đồng"}</div>
                            <button className="text-slate-500 hover:text-slate-700" onClick={() => setShow(false)}>
                                Đóng
                            </button>
                        </div>

                        <form onSubmit={save} className="p-5 grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className="text-sm text-slate-600">Mã hợp đồng</label>
                                <input
                                    value={form.contractCode}
                                    onChange={(e) => setForm((f) => ({ ...f, contractCode: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Khách hàng</label>
                                <select
                                    required
                                    value={form.customerId}
                                    onChange={(e) => setForm((f) => ({ ...f, customerId: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                >
                                    <option value="">— Chọn khách hàng —</option>
                                    {customers.map((c) => (
                                        <option key={c.id} value={c.id}>
                                            {c.name}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            <div className="md:col-span-2">
                                <label className="text-sm text-slate-600">Tiêu đề</label>
                                <input
                                    required
                                    value={form.title}
                                    onChange={(e) => setForm((f) => ({ ...f, title: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                    placeholder="VD: Thi công nhà xưởng A - Phase 1"
                                />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Giá trị (đ)</label>
                                <input
                                    required
                                    type="number"
                                    min="0"
                                    value={form.totalAmount}
                                    onChange={(e) => setForm((f) => ({ ...f, totalAmount: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Ngày ký</label>
                                <input
                                    type="date"
                                    value={form.signedDate}
                                    onChange={(e) => setForm((f) => ({ ...f, signedDate: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Ngày hết hạn</label>
                                <input
                                    type="date"
                                    value={form.dueDate}
                                    onChange={(e) => setForm((f) => ({ ...f, dueDate: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Loại hợp đồng</label>
                                <select
                                    value={form.contractType}
                                    onChange={(e) => setForm((f) => ({ ...f, contractType: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                >
                                    {CONTRACT_TYPES.map((t) => (
                                        <option key={t.value} value={t.value}>
                                            {t.label}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Trạng thái</label>
                                <select
                                    value={form.status}
                                    onChange={(e) => setForm((f) => ({ ...f, status: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                >
                                    {CONTRACT_STATUSES.map((s) => (
                                        <option key={s.value} value={s.value}>
                                            {s.label}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            <div className="md:col-span-2 flex items-center justify-end gap-2 pt-2">
                                <button
                                    type="button"
                                    className="px-3 py-2 rounded-lg bg-slate-100 hover:bg-slate-200"
                                    onClick={() => setShow(false)}
                                >
                                    Huỷ
                                </button>
                                <button className="px-4 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">
                                    Lưu
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}
